const precoProdutoA = 100;
const descontoProdutoA = 10;
const precoFinalA = precoProdutoA - descontoProdutoA;
console.log('Preço final do produto A: R$ ' + precoFinalA);

const precoProdutoB = 200;
const descontoProdutoB = 25;
const precoFinalB = precoProdutoB - descontoProdutoB;
console.log('Preço final do produto B: R$ ' + precoFinalB);

function calcularPrecoFinal(preco, desconto) {
  return preco - desconto;
}

const precoFinalA = calcularPrecoFinal(100, 10);
const precoFinalB = calcularPrecoFinal(200, 25);

console.log(precoFinalA);
console.log(precoFinalB);

function calcularPrecoFinal(preco, desconto) {
  return preco - desconto;
}

function montarMensagemPrecoFinal(nomeProduto, precoFinal) {
  return 'Preço final do ' + nomeProduto + ': R$ ' + precoFinal;
}

const precoFinalA = calcularPrecoFinal(100, 10);
const precoFinalB = calcularPrecoFinal(200, 25);

const mensagemA = montarMensagemPrecoFinal('produto A', precoFinalA);
const mensagemB = montarMensagemPrecoFinal('produto B', precoFinalB);

console.log(mensagemA);
console.log(mensagemB);
